#include <iostream>
#include <string>
#include <string_view>

class Base
{
public:
    Base() { std::cout << "Base constructed\n"; }
    ~Base() { std::cout << "Base destroyed\n"; }
};

class Derived : public Base
{
    std::string m_name;

public:
    Derived(std::string_view name)
        : m_name{ name }
    {
        std::cout << "Derived(" << m_name << ") constructed\n";
    }

    ~Derived()
    {
        std::cout << "Derived(" << m_name << ") destroyed\n";
    }
};

int main()
{
    std::string firstName{};
    std::string secondName{};
    std::cin >> firstName >> secondName;

    {
        Derived first{ firstName };
        Derived second{ secondName };
    }

    return 0;
}

